/**
 * Adapter: UI and utility re-exports for copy-standalone portability.
 *
 * When copying this component to another project, update these imports
 * to match your project's paths:
 *
 *   cn           → Your Tailwind merge utility (e.g., "@/lib/utils", "~/lib/cn")
 *   Button       → shadcn/ui Button
 *   Switch       → shadcn/ui Switch
 *   ToggleGroup  → shadcn/ui ToggleGroup
 *   Select       → shadcn/ui Select
 *   Separator    → shadcn/ui Separator
 *   Label        → shadcn/ui Label
 */

export { cn } from "@/lib/utils";
export { Button } from "@/components/ui/button";
export { Switch } from "@/components/ui/switch";
export {
  ToggleGroup,
  ToggleGroupItem,
} from "@/components/ui/toggle-group";
export {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
export { Separator } from "@/components/ui/separator";
export { Label } from "@/components/ui/label";

"use client";

import {
  ToolUIErrorBoundary,
  type ToolUIErrorBoundaryProps,
} from "@/components/tool-ui/shared";

export function PreferencesPanelErrorBoundary(
  props: Omit<ToolUIErrorBoundaryProps, "componentName">,
) {
  const { children, ...rest } = props;
  return (
    <ToolUIErrorBoundary componentName="PreferencesPanel" {...rest}>
      {children}
    </ToolUIErrorBoundary>
  );
}

export { PreferencesPanel, PreferencesPanelReceipt } from "./preferences-panel";
export { PreferencesPanelErrorBoundary } from "./error-boundary";
export {
  SerializablePreferencesPanelSchema,
  SerializablePreferencesPanelReceiptSchema,
  parseSerializablePreferencesPanel,
  parseSerializablePreferencesPanelReceipt,
  type SerializablePreferencesPanel,
  type SerializablePreferencesPanelReceipt,
  type PreferencesPanelProps,
  type PreferencesPanelReceiptProps,
  type PreferencesValue,
  type PreferenceItem,
  type PreferenceSection,
} from "./schema";

"use client";

import { useCallback, useMemo, useState } from "react";
import type {
  PreferencesPanelProps,
  PreferencesPanelReceiptProps,
  PreferencesValue,
  PreferenceItem,
  PreferenceSection,
} from "./schema";
import { ActionButtons, normalizeActionsConfig } from "@/components/tool-ui/shared";
import type { Action } from "@/components/tool-ui/shared";
import {
  cn,
  Switch,
  ToggleGroup,
  ToggleGroupItem,
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
  Separator,
  Label,
} from "./_adapter";
import { Check, AlertCircle } from "lucide-react";

function getInitialValue(item: PreferenceItem): string | boolean {
  switch (item.type) {
    case "switch":
      return item.defaultChecked ?? false;
    case "toggle":
      return item.defaultValue ?? item.options?.[0]?.value ?? "";
    case "select":
      return item.defaultSelected ?? item.selectOptions?.[0]?.value ?? "";
  }
}

function formatDisplayValue(item: PreferenceItem, value: string | boolean): string {
  if (item.type === "switch") {
    return typeof value === "boolean" && value ? "On" : "Off";
  }

  const stringValue = typeof value === "string" ? value : "";
  const options = item.type === "toggle" ? item.options : item.selectOptions;
  const option = options?.find((opt) => opt.value === stringValue);

  return option?.label ?? stringValue;
}

function computeInitialValues(sections: PreferenceSection[]): PreferencesValue {
  return sections.reduce<PreferencesValue>((acc, section) => {
    section.items.forEach((item) => {
      acc[item.id] = getInitialValue(item);
    });
    return acc;
  }, {});
}

interface PreferenceControlProps {
  item: PreferenceItem;
  value: string | boolean;
  onChange: (value: string | boolean) => void;
  disabled?: boolean;
}

function SwitchControl({ id, checked, onChange, disabled, label }: {
  id: string;
  checked: boolean;
  onChange: (value: boolean) => void;
  disabled?: boolean;
  label: string;
}) {
  return (
    <Switch
      id={id}
      checked={checked}
      onCheckedChange={onChange}
      disabled={disabled}
      aria-label={label}
    />
  );
}

function ToggleControl({ value, options, onChange, disabled, label }: {
  value: string;
  options: Array<{ value: string; label: string }>;
  onChange: (value: string) => void;
  disabled?: boolean;
  label: string;
}) {
  return (
    <ToggleGroup
      type="single"
      value={value}
      onValueChange={(v) => v && onChange(v)}
      disabled={disabled}
      aria-label={label}
      className="gap-1"
    >
      {options.map((opt) => (
        <ToggleGroupItem
          key={opt.value}
          value={opt.value}
          aria-label={opt.label}
          className="!rounded-full px-3 py-1.5 text-sm"
        >
          {opt.label}
        </ToggleGroupItem>
      ))}
    </ToggleGroup>
  );
}

function SelectControl({ id, value, options, onChange, disabled, label }: {
  id: string;
  value: string;
  options: Array<{ value: string; label: string }>;
  onChange: (value: string) => void;
  disabled?: boolean;
  label: string;
}) {
  return (
    <Select
      value={value}
      onValueChange={onChange}
      disabled={disabled}
    >
      <SelectTrigger
        id={id}
        className="w-[180px]"
        aria-label={label}
      >
        <SelectValue placeholder="Select..." />
      </SelectTrigger>
      <SelectContent>
        {options.map((opt) => (
          <SelectItem key={opt.value} value={opt.value}>
            {opt.label}
          </SelectItem>
        ))}
      </SelectContent>
    </Select>
  );
}

function PreferenceControl({ item, value, onChange, disabled }: PreferenceControlProps) {
  const id = `preference-${item.id}`;

  if (item.type === "switch") {
    return (
      <SwitchControl
        id={id}
        checked={typeof value === "boolean" ? value : false}
        onChange={onChange}
        disabled={disabled}
        label={item.label}
      />
    );
  }

  const stringValue = typeof value === "string" ? value : "";

  if (item.type === "toggle" && item.options) {
    return (
      <ToggleControl
        value={stringValue}
        options={item.options}
        onChange={onChange}
        disabled={disabled}
        label={item.label}
      />
    );
  }

  if (item.type === "select" && item.selectOptions) {
    return (
      <SelectControl
        id={id}
        value={stringValue}
        options={item.selectOptions}
        onChange={onChange}
        disabled={disabled}
        label={item.label}
      />
    );
  }

  return null;
}

interface PreferenceItemRowProps {
  item: PreferenceItem;
  value: string | boolean;
  onChange?: (value: string | boolean) => void;
  disabled?: boolean;
  isReceipt?: boolean;
  error?: string;
  showSuccessIndicators?: boolean;
  isFirstInSectionWithoutHeading?: boolean;
}

function ItemLabel({ item, error, isReceipt }: {
  item: PreferenceItem;
  error?: string;
  isReceipt: boolean;
}) {
  const htmlFor = `preference-${item.id}`;

  if (isReceipt) {
    return (
      <>
        <span className="text-sm font-medium leading-6 text-pretty">{item.label}</span>
        {error ? (
          <span className="text-destructive text-sm font-normal text-pretty">
            {error}
          </span>
        ) : item.description ? (
          <span className="text-muted-foreground text-sm font-normal text-pretty">
            {item.description}
          </span>
        ) : null}
      </>
    );
  }

  return (
    <>
      <Label htmlFor={htmlFor} className="font-medium leading-6 text-pretty">
        {item.label}
      </Label>
      {item.description && (
        <p className="text-muted-foreground text-sm font-normal text-pretty">
          {item.description}
        </p>
      )}
    </>
  );
}

function ItemValue({ item, value, error, showSuccessIndicators }: {
  item: PreferenceItem;
  value: string | boolean;
  error?: string;
  showSuccessIndicators: boolean;
}) {
  const displayValue = formatDisplayValue(item, value);

  return (
    <div className="flex shrink-0 items-center gap-2">
      <span className="text-muted-foreground text-sm font-medium">
        {displayValue}
      </span>
      {error ? (
        <AlertCircle className="text-destructive size-3.5" />
      ) : showSuccessIndicators ? (
        <Check className="text-emerald-600 dark:text-emerald-500 size-3.5" />
      ) : null}
    </div>
  );
}

function PreferenceItemRow({
  item,
  value,
  onChange,
  disabled,
  isReceipt = false,
  error,
  showSuccessIndicators = false,
  isFirstInSectionWithoutHeading = false,
}: PreferenceItemRowProps) {
  const shouldStack = item.type !== "switch" && !isReceipt;

  return (
    <div
      className={cn(
        "flex items-start justify-between gap-4",
        isFirstInSectionWithoutHeading ? "pt-0 pb-3" : "py-3",
        shouldStack && "flex-col gap-3 @sm/preferences-panel:flex-row @sm/preferences-panel:gap-4"
      )}
    >
      <div className="flex flex-col gap-1">
        <ItemLabel item={item} error={error} isReceipt={isReceipt} />
      </div>

      {isReceipt ? (
        <ItemValue
          item={item}
          value={value}
          error={error}
          showSuccessIndicators={showSuccessIndicators}
        />
      ) : (
        <div className="flex shrink-0">
          <PreferenceControl
            item={item}
            value={value}
            onChange={onChange!}
            disabled={disabled}
          />
        </div>
      )}
    </div>
  );
}

interface ItemListProps {
  items: PreferenceItem[];
  values: PreferencesValue;
  onChangeValue?: (itemId: string, value: string | boolean) => void;
  disabled?: boolean;
  isReceipt?: boolean;
  errors?: Record<string, string>;
  showSuccessIndicators?: boolean;
  hasHeading?: boolean;
  hasTitle?: boolean;
}

function ItemList({
  items,
  values,
  onChangeValue,
  disabled,
  isReceipt,
  errors,
  showSuccessIndicators,
  hasHeading = false,
  hasTitle = false,
}: ItemListProps) {
  const shouldRemoveFirstPadding = !hasHeading && hasTitle;

  return (
    <div className="flex flex-col">
      {items.map((item, index) => {
        const isFirst = index === 0;
        const itemValue = values[item.id] ?? getInitialValue(item);
        const handleChange = onChangeValue
          ? (v: string | boolean) => onChangeValue(item.id, v)
          : undefined;

        return (
          <div key={item.id}>
            {!isFirst && <Separator className="my-1" />}
            <PreferenceItemRow
              item={item}
              value={itemValue}
              onChange={handleChange}
              disabled={disabled}
              isReceipt={isReceipt}
              error={errors?.[item.id]}
              showSuccessIndicators={showSuccessIndicators}
              isFirstInSectionWithoutHeading={isFirst && shouldRemoveFirstPadding}
            />
          </div>
        );
      })}
    </div>
  );
}

interface PreferencesSectionProps {
  section: PreferenceSection;
  values: PreferencesValue;
  onChangeValue?: (itemId: string, value: string | boolean) => void;
  disabled?: boolean;
  isReceipt?: boolean;
  errors?: Record<string, string>;
  hasTitle?: boolean;
}

function PreferencesSection({
  section,
  values,
  onChangeValue,
  disabled,
  isReceipt = false,
  errors,
  hasTitle = false,
}: PreferencesSectionProps) {
  const hasErrors = !!(errors && Object.keys(errors).length > 0);

  const content = (
    <ItemList
      items={section.items}
      values={values}
      onChangeValue={onChangeValue}
      disabled={disabled}
      isReceipt={isReceipt}
      errors={errors}
      showSuccessIndicators={hasErrors}
      hasHeading={!!section.heading}
      hasTitle={hasTitle}
    />
  );

  if (section.heading) {
    return (
      <fieldset className="flex flex-col">
        <legend className="text-muted-foreground text-xs tracking-widest uppercase pb-1">
          {section.heading}
        </legend>
        {content}
      </fieldset>
    );
  }

  return content;
}

interface ReceiptHeaderProps {
  title: string;
  hasErrors: boolean;
}

function ReceiptHeader({ title, hasErrors }: ReceiptHeaderProps) {
  return (
    <>
      <div className="flex items-center justify-between gap-3 px-5 py-4">
        <h2 className="text-base font-semibold leading-none">{title}</h2>
        {hasErrors === true ? (
          <span className="text-destructive flex items-center gap-1.5 text-xs font-medium">
            <AlertCircle className="size-3.5" />
            Error
          </span>
        ) : (
          <span className="text-emerald-600 dark:text-emerald-500 flex items-center gap-1.5 text-xs font-medium">
            <Check className="size-3.5" />
            Saved
          </span>
        )}
      </div>
      <Separator />
    </>
  );
}

export function PreferencesPanelReceipt({
  id,
  title,
  sections,
  choice,
  error,
  className,
}: PreferencesPanelReceiptProps) {
  const hasErrors = error && Object.keys(error).length > 0;

  return (
    <article
      data-slot="preferences-panel"
      data-tool-ui-id={id}
      data-receipt="true"
      role="status"
      aria-label={hasErrors ? "Preferences with errors" : "Confirmed preferences"}
      className={cn("@container/preferences-panel flex w-full max-w-md min-w-80 flex-col", className)}
    >
      <div className="bg-card/60 flex w-full flex-col rounded-2xl border opacity-95 shadow-xs overflow-hidden">
        {title && <ReceiptHeader title={title} hasErrors={!!hasErrors} />}
        <div className={cn("px-5 flex flex-col gap-4", title ? "py-6" : "py-2")}>
          {sections.map((section, index) => (
            <div key={index}>
              <PreferencesSection
                section={section}
                values={choice}
                errors={error}
                isReceipt={true}
                hasTitle={!!title}
              />
            </div>
          ))}
        </div>
      </div>
    </article>
  );
}

function PreferencesPanelRoot({
  id,
  title,
  sections,
  value: controlledValue,
  onChange,
  onSave,
  onCancel,
  responseActions,
  onResponseAction,
  onBeforeResponseAction,
  className,
}: PreferencesPanelProps) {
  const initialValues = useMemo(() => computeInitialValues(sections), [sections]);

  const [uncontrolledValue, setUncontrolledValue] = useState<PreferencesValue>(initialValues);

  const currentValue = controlledValue ?? uncontrolledValue;

  const updateValue = useCallback(
    (itemId: string, newValue: string | boolean) => {
      const nextValue = { ...currentValue, [itemId]: newValue };
      if (controlledValue === undefined) {
        setUncontrolledValue(nextValue);
      }
      onChange?.(nextValue);
    },
    [currentValue, controlledValue, onChange],
  );

  const isDirty = useMemo(() => {
    return Object.keys(currentValue).some(
      (key) => currentValue[key] !== initialValues[key],
    );
  }, [currentValue, initialValues]);

  const handleSave = useCallback(async () => {
    await onSave?.(currentValue);
  }, [onSave, currentValue]);

  const handleCancel = useCallback(() => {
    if (controlledValue === undefined) {
      setUncontrolledValue(initialValues);
    }
    onChange?.(initialValues);
    onCancel?.();
  }, [controlledValue, initialValues, onChange, onCancel]);

  const handleAction = useCallback(
    async (actionId: string) => {
      if (actionId === "save") {
        await handleSave();
      } else if (actionId === "cancel") {
        handleCancel();
      }
      await onResponseAction?.(actionId, currentValue);
    },
    [handleSave, handleCancel, onResponseAction, currentValue],
  );

  const normalizedActions = useMemo(() => {
    const normalized = normalizeActionsConfig(responseActions);
    if (normalized) {
      return {
        ...normalized,
        align: normalized.align ?? ("right" as const),
      };
    }

    const defaultActions: Action[] = [
      { id: "cancel", label: "Cancel", variant: "ghost" },
      { id: "save", label: "Save Changes", variant: "default" },
    ];

    return {
      items: defaultActions,
      align: "right" as const,
    };
  }, [responseActions]);

  const actionsWithState = useMemo((): Action[] => {
    return normalizedActions.items.map((action) => {
      const isSaveAction = action.id === "save";
      const baseDisabled = "disabled" in action ? action.disabled : false;
      const shouldDisable = baseDisabled || (isSaveAction && !isDirty);

      return {
        ...action,
        disabled: shouldDisable,
      };
    });
  }, [normalizedActions.items, isDirty]);

  return (
    <article
      data-slot="preferences-panel"
      data-tool-ui-id={id}
      role="form"
      className={cn("@container/preferences-panel flex w-full max-w-md min-w-80 flex-col gap-3 text-foreground", className)}
    >
      <div className="bg-card flex w-full flex-col rounded-2xl border shadow-xs overflow-hidden">
        {title && (
          <>
            <div className="px-5 py-4">
              <h2 className="text-base font-semibold leading-none">{title}</h2>
            </div>
            <Separator />
          </>
        )}
        <div className={cn("px-5 flex flex-col gap-4", title ? "py-6" : "py-2")}>
          {sections.map((section, sectionIndex) => (
            <div key={sectionIndex}>
              <PreferencesSection
                section={section}
                values={currentValue}
                onChangeValue={updateValue}
                isReceipt={false}
                hasTitle={!!title}
              />
            </div>
          ))}
        </div>
      </div>

      <div className="@container/actions">
        <ActionButtons
          actions={actionsWithState}
          align={normalizedActions.align}
          confirmTimeout={normalizedActions.confirmTimeout}
          onAction={handleAction}
          onBeforeAction={onBeforeResponseAction}
        />
      </div>
    </article>
  );
}

type PreferencesPanelComponent = typeof PreferencesPanelRoot & {
  Receipt: typeof PreferencesPanelReceipt;
};

export const PreferencesPanel = Object.assign(PreferencesPanelRoot, {
  Receipt: PreferencesPanelReceipt,
}) as PreferencesPanelComponent;

import { z } from "zod";
import type { ActionsProp } from "@/components/tool-ui/shared";
import {
  SerializableActionSchema,
  SerializableActionsConfigSchema,
  ToolUIIdSchema,
  ToolUIReceiptSchema,
  ToolUIRoleSchema,
  parseWithSchema,
} from "@/components/tool-ui/shared";

const PreferenceItemBaseSchema = z.object({
  id: z.string().min(1),
  label: z.string().min(1),
  description: z.string().optional(),
});

const PreferenceSwitchSchema = PreferenceItemBaseSchema.extend({
  type: z.literal("switch"),
  defaultChecked: z.boolean().optional(),
});

const PreferenceToggleSchema = PreferenceItemBaseSchema.extend({
  type: z.literal("toggle"),
  options: z
    .array(
      z.object({
        value: z.string().min(1),
        label: z.string().min(1),
      }),
    )
    .min(2),
  defaultValue: z.string().optional(),
});

const PreferenceSelectSchema = PreferenceItemBaseSchema.extend({
  type: z.literal("select"),
  selectOptions: z
    .array(
      z.object({
        value: z.string().min(1),
        label: z.string().min(1),
      }),
    )
    .min(5),
  defaultSelected: z.string().optional(),
});

const PreferenceItemSchema = z.discriminatedUnion("type", [
  PreferenceSwitchSchema,
  PreferenceToggleSchema,
  PreferenceSelectSchema,
]);

const PreferenceSectionSchema = z.object({
  heading: z.string().min(1).optional(),
  items: z.array(PreferenceItemSchema).min(1),
});

const PreferencesPanelBaseSchema = z.object({
  id: ToolUIIdSchema,
  role: ToolUIRoleSchema.optional(),
  receipt: ToolUIReceiptSchema.optional(),
  title: z.string().min(1).optional(),
  sections: z.array(PreferenceSectionSchema).min(1),
});

export const SerializablePreferencesPanelSchema = PreferencesPanelBaseSchema.extend({
  responseActions: z
    .union([
      z.array(SerializableActionSchema),
      SerializableActionsConfigSchema,
    ])
    .optional(),
});

export const SerializablePreferencesPanelReceiptSchema =
  PreferencesPanelBaseSchema.extend({
    choice: z.record(z.string(), z.union([z.string(), z.boolean()])),
    error: z.record(z.string(), z.string()).optional(),
  });

export type SerializablePreferencesPanel = z.infer<
  typeof SerializablePreferencesPanelSchema
>;

export type SerializablePreferencesPanelReceipt = z.infer<
  typeof SerializablePreferencesPanelReceiptSchema
>;

export function parseSerializablePreferencesPanel(
  input: unknown,
): SerializablePreferencesPanel {
  return parseWithSchema(
    SerializablePreferencesPanelSchema,
    input,
    "PreferencesPanel",
  );
}

export function parseSerializablePreferencesPanelReceipt(
  input: unknown,
): SerializablePreferencesPanelReceipt {
  return parseWithSchema(
    SerializablePreferencesPanelReceiptSchema,
    input,
    "PreferencesPanelReceipt",
  );
}

export interface PreferencesValue {
  [itemId: string]: string | boolean;
}

export interface PreferencesPanelProps
  extends Omit<SerializablePreferencesPanel, "responseActions"> {
  className?: string;
  value?: PreferencesValue;
  onChange?: (value: PreferencesValue) => void;
  onSave?: (value: PreferencesValue) => void | Promise<void>;
  onCancel?: () => void;
  responseActions?: ActionsProp;
  onResponseAction?: (
    actionId: string,
    value: PreferencesValue,
  ) => void | Promise<void>;
  onBeforeResponseAction?: (actionId: string) => boolean | Promise<boolean>;
}

export interface PreferencesPanelReceiptProps
  extends SerializablePreferencesPanelReceipt {
  className?: string;
}

export type PreferenceItem = z.infer<typeof PreferenceItemSchema>;
export type PreferenceSection = z.infer<typeof PreferenceSectionSchema>;
